{# ── Collect & sort items by Outer Box then Inner Box ── #}
{% set items = doc.shree_packing_boxes %}

{% set result_list = [] %}
{% for row in items %}
    {% set row_dict = {
        'no'       : row.no,
        'inner_box': row.inner_box,
        'outer_box': row.outer_box,
        'item_code': row.item_code,
        'qty'      : row.qty,
        'item_name': row.item_name,
        'uom'      : row.uom
    } %}
    {% set _ = result_list.append(row_dict) %}
{% endfor %}

{# Sort by outer_box (numeric) first, then inner_box (numeric) #}
{% set result_list2 = [] %}
{% for row in result_list %}
    {% set _ = row.update({'outer_box_int': row.outer_box | string | replace('Box ','') | int(0), 'inner_box_int': row.inner_box | int(0)}) %}
    {% set _ = result_list2.append(row) %}
{% endfor %}
{% set sorted_list = result_list2 | sort(attribute='inner_box_int') | sort(attribute='outer_box_int') %}

{# Re-index after sort #}
{% for row in sorted_list %}
    {% set _ = row.update({'idx': loop.index}) %}
{% endfor %}

