</table>

{# ══════════════════ ITEMS TABLE ══════════════════ #}
{# Columns: # | Outer Box | Inner Box | Item Name | Qty | UOM  → 6 columns #}
<table width="100%" class="table table-bordered" border="1" style="margin-top:-21px;">
    <thead>
        <tr bgcolor="Lavender">
            <th width="5%"  align="center">#</th>
            <th width="8%"  align="center">Outer Box</th>
            <th width="8%"  align="center">Inner Box</th>
            <th width="59%" align="left">Item Name</th>
            <th width="12%" align="right">Qty</th>
            <th width="8%"  align="center">UOM</th>
        </tr>
    </thead>
    <tbody>
        {% set ns = namespace(total_qty=0, prev_outer='') %}
        {% for item in sorted_list %}
            <tr>
                <td width="5%"  align="center">{{ item['idx'] }}</td>
                <td width="8%"  align="center">
                    {%- if item['outer_box'] != ns.prev_outer -%}
                        <b>{{ item['outer_box'] }}</b>
                        {% set ns.prev_outer = item['outer_box'] %}
                    {%- else -%}
                        {{ item['outer_box'] }}
                    {%- endif -%}
                </td>
                <td width="8%"  align="center">{{ item['inner_box'] }}</td>
                <td width="59%" align="left">{{ item['item_name'] }}</td>
                <td width="12%" align="right">{{ item['qty'] | int }}</td>
                <td width="8%"  align="center">{{ item['uom'] }}</td>
            </tr>
            {% set ns.total_qty = ns.total_qty + item['qty'] | int %}
        {% endfor %}
        {# ── Totals row — colspan 4 covers #, Outer, Inner, Item Name ── #}
        <tr>
            <td colspan="4" align="right" style="font-weight:bold;"><i>TOTAL</i></td>
            <td align="right" style="font-weight:bold;">{{ ns.total_qty }}</td>
            <td align="center"></td>
        </tr>
    </tbody>
</table>

{# ══════════════════ OUTER BOX SUMMARY ══════════════════ #}
{% set box_summary = {} %}
{% for item in sorted_list %}
    {% set ob = item['outer_box'] %}
    {% if ob not in box_summary %}
        {% set _ = box_summary.update({ob: {'qty': 0, 'items': []}}) %}
    {% endif %}
    {% set entry = box_summary[ob] %}
    {% set new_qty = entry['qty'] + item['qty'] | int %}
    {% set new_items = entry['items'] %}
    {% if item['item_name'] not in new_items %}
        {% set _ = new_items.append(item['item_name']) %}
    {% endif %}
    {% set _ = box_summary.update({ob: {'qty': new_qty, 'items': new_items}}) %}
{% endfor %}
